function Badge({status,map=SC,label}){const cfg=map[status]||{color:"#666",bg:"rgba(102,102,102,0.12)"};return(<span style={{display:"inline-flex",alignItems:"center",gap:4,fontSize:11,fontWeight:500,color:cfg.color,background:cfg.bg,padding:"2px 8px",borderRadius:D.rF,whiteSpace:"nowrap",border:`1px solid ${cfg.color}20`,fontFamily:D.font}}>{cfg.dot&&<span style={{width:5,height:5,borderRadius:"50%",background:cfg.color,flexShrink:0}}/>}{label}</span>);}
function Pbar({v,color=D.green,h=2}){return(<div style={{height:h,background:"rgba(255,255,255,0.06)",borderRadius:h,overflow:"hidden"}}><div style={{width:`${Math.min(v,100)}%`,height:"100%",background:color,borderRadius:h,transition:"width 1.2s ease"}}/></div>);}
function Num({v,pre="",suf="",dec=0}){const[d,setD]=useState(0);useEffect(()=>{let s=0,step=v/50;const t=setInterval(()=>{s+=step;if(s>=v){setD(v);clearInterval(t);}else setD(s);},16);return()=>clearInterval(t);},[v]);const f=d>=1e6?(d/1e6).toFixed(1)+"M":d>=1e3?(d/1e3).toFixed(1)+"K":d.toFixed(dec);return <span>{pre}{f}{suf}</span>;}
function Spark({data,color}){const max=Math.max(...data),min=Math.min(...data);const pts=data.map((v,i)=>{const x=i*(56/(data.length-1));const y=20-((v-min)/(max-min||1))*16;return `${x},${y}`;}).join(" ");return(<svg width="60" height="24" viewBox="0 0 60 24" fill="none"><polyline points={pts} stroke={color} strokeWidth="1.5" strokeLinecap="round" strokeLinejoin="round" opacity="0.7"/><circle cx="56" cy={20-((data[data.length-1]-min)/(max-min||1))*16} r="2" fill={color}/></svg>);}
function BarChart({data}){const max=Math.max(...data.map(d=>d.rev));return(<svg width="100%" height="100%" viewBox="0 0 320 90" preserveAspectRatio="none"><defs><linearGradient id="bg" x1="0" y1="0" x2="0" y2="1"><stop offset="0%" stopColor={D.green} stopOpacity="0.5"/><stop offset="100%" stopColor={D.green} stopOpacity="0.02"/></linearGradient></defs>{data.map((d,i)=>{const bh=(d.rev/max)*68,x=i*46+4;return(<g key={i}><rect x={x} y={72-bh} width={38} height={bh} fill="url(#bg)" rx="3"/><rect x={x} y={72-bh} width={38} height="1.5" fill={D.green} rx="1"/><text x={x+19} y={86} textAnchor="middle" fontSize="9" fill={D.textM} fontFamily={D.font}>{d.day}</text></g>);})}<line x1="0" y1="73" x2="320" y2="73" stroke="rgba(255,255,255,0.05)" strokeWidth="0.5"/></svg>);}
