function Btn({children,onClick,variant="primary",size="md",icon,disabled,style={}}){const sz={sm:"4px 10px",md:"7px 14px",lg:"10px 20px"};const vs={primary:{background:D.green,color:"#000",border:"none"},ghost:{background:"transparent",color:D.text,border:`1px solid ${D.border}`},danger:{background:D.redD,color:D.red,border:`1px solid rgba(239,68,68,0.2)`},success:{background:D.greenD,color:D.green,border:`1px solid rgba(16,185,129,0.2)`},amber:{background:D.amberD,color:D.amber,border:`1px solid rgba(245,158,11,0.2)`}};const v=vs[variant]||vs.primary;return(<button disabled={disabled} onClick={onClick} style={{display:"inline-flex",alignItems:"center",gap:5,padding:sz[size],borderRadius:D.r,fontSize:12,fontWeight:500,cursor:disabled?"not-allowed":"pointer",fontFamily:D.font,transition:"opacity .15s",opacity:disabled?0.5:1,whiteSpace:"nowrap",...v,...style}} onMouseEnter={e=>{if(!disabled)e.currentTarget.style.opacity=".75";}} onMouseLeave={e=>e.currentTarget.style.opacity="1"}>{icon&&<I n={icon} size={13}/>}{children}</button>);}
